 59	void nfapi_pnf_phy_config_delete_all(nfapi_pnf_config_t* config)
 60	{
 61		nfapi_pnf_phy_config_t* curr = config->phys;
 62		while(curr != 0)
 63		{
 64			nfapi_pnf_phy_config_t* to_delete = curr;
 65			curr = curr->next;
 66			free(to_delete);
 67		}
 68	
 69		config->phys = 0;
 70	}
